from flask import Flask, request, jsonify
from collections import Counter

app = Flask(__name__)

# Initialize data storage
labeled_images = {}

@app.route("/label", methods=["POST"])
def label_image():
    image_id = request.json["image_id"]
    label = request.json["label"]

    if image_id not in labeled_images:
        labeled_images[image_id] = []

    labeled_images[image_id].append(label)

    return jsonify({"status": "success"})

@app.route("/aggregate_labels", methods=["GET"])
def aggregate_labels():
    aggregated_labels = {}

    for image_id, labels in labeled_images.items():
        label_counts = Counter(labels)
        majority_label = label_counts.most_common(1)[0][0]
        aggregated_labels[image_id] = majority_label

    return jsonify(aggregated_labels)

